def _ts_col(df):
    for c in ["timestamp","time","datetime","date"]:
        if c in df.columns: return c
    for c in df.columns:
        if "time" in c.lower() or "date" in c.lower(): return c
    return None

def _num_cols(df, exclude=()):
    return [c for c in df.columns if c not in exclude and pd.api.types.is_numeric_dtype(df[c])]

def _safe_window(df, tcol, start, end):
    if df is None or len(df)==0 or tcol is None: return pd.DataFrame()
    x=df.copy()
    x[tcol]=pd.to_datetime(x[tcol])
    return x[(x[tcol]>=start)&(x[tcol]<end)].copy()

def _angular_diff(a,b):
    return abs((a-b+180)%360-180)

