# 3) 空气质量站点/扬尘站点：峰值同步响应、下风向响应
def _station_response(aq_df, meta_df=None, station_id_col="station_id"):
    out = {"records_in_window": 0, "records_at_peak": 0, "pollutant_peak_minus_pre6h": {}, "pollutant_post6h_minus_pre6h": {}}
    df = aq_df.copy() if isinstance(aq_df, pd.DataFrame) else pd.DataFrame()
    t = _ts_col(df)
    if df.empty or not t:
        out["note"] = "未取得可用于逐小时响应对比的数据"
        return out, pd.DataFrame()
    df[t]=pd.to_datetime(df[t])
    dwin=_safe_window(df,t,spike_cause_start,spike_cause_end_exclusive)
    dpeak=dwin[dwin[t].eq(spike_cause_peak_ts)]
    pre=_safe_window(df,t,spike_cause_peak_ts-pd.Timedelta(hours=6),spike_cause_peak_ts)
    post=_safe_window(df,t,spike_cause_peak_ts+pd.Timedelta(hours=1),spike_cause_peak_ts+pd.Timedelta(hours=7))
    pollutants=[c for c in ["aqi","pm2_5","pm10","so2","no2","co","o3","o3_8h","composite_index"] if c in dwin.columns]
    out["records_in_window"]=int(len(dwin)); out["records_at_peak"]=int(len(dpeak))
    out["pollutant_peak_mean"]={c: (None if dpeak[c].dropna().empty else float(dpeak[c].mean())) for c in pollutants}
    out["pollutant_pre6h_mean"]={c: (None if pre[c].dropna().empty else float(pre[c].mean())) for c in pollutants}
    out["pollutant_post6h_mean"]={c: (None if post[c].dropna().empty else float(post[c].mean())) for c in pollutants}
    for c in pollutants:
        out["pollutant_peak_minus_pre6h"][c]=None if out["pollutant_peak_mean"][c] is None or out["pollutant_pre6h_mean"][c] is None else float(out["pollutant_peak_mean"][c]-out["pollutant_pre6h_mean"][c])
        out["pollutant_post6h_minus_pre6h"][c]=None if out["pollutant_post6h_mean"][c] is None or out["pollutant_pre6h_mean"][c] is None else float(out["pollutant_post6h_mean"][c]-out["pollutant_pre6h_mean"][c])
    return out, dpeak

