        # 自动寻找站点方位列；若无则用经纬度计算近似方位
        bearing_col = next((c for c in meta.columns if "bearing" in c.lower() or "azimuth" in c.lower() or "direction_from_company" in c.lower()), None)
        idcol = "station_id" if "station_id" in meta.columns else ("id" if "id" in meta.columns else None)
        if bearing_col:
            meta["_bearing_from_company"] = pd.to_numeric(meta[bearing_col], errors="coerce")
        else:
            lat_col = next((c for c in meta.columns if c.lower() in ["lat","latitude","station_lat","aq_lat"]), None)
            lon_col = next((c for c in meta.columns if c.lower() in ["lon","longitude","station_lon","aq_lon"]), None)
            if lat_col and lon_col:
                lat1=np.deg2rad(float(da_company_lat)); lat2=np.deg2rad(pd.to_numeric(meta[lat_col], errors="coerce"))
                dlon=np.deg2rad(pd.to_numeric(meta[lon_col], errors="coerce")-float(da_company_lon))
                y=np.sin(dlon)*np.cos(lat2); x=np.cos(lat1)*np.sin(lat2)-np.sin(lat1)*np.cos(lat2)*np.cos(dlon)
                meta["_bearing_from_company"]=(np.degrees(np.arctan2(y,x))+360)%360
        if "_bearing_from_company" in meta.columns:
            meta["_angle_to_plume"] = meta["_bearing_from_company"].apply(lambda x: np.nan if pd.isna(x) else _angular_diff(float(x), plume_to))
            meta["_downwind_45deg"] = meta["_angle_to_plume"] <= 45
            down_ids = set(meta.loc[meta["_downwind_45deg"] & meta[idcol].notna(), idcol].astype(int)) if idcol else set()
