                peak["_downwind_45deg"]=peak[peak_id].isin(down_ids)
                grp=peak.groupby("_downwind_45deg")[pols].mean().round(4)
                spike_cause_downwind_station_summary = {
                    "available": True,
                    "wind_from_degree": float(wind_from),
                    "plume_to_degree": float(plume_to),
                    "nearby_station_count_with_bearing": int(meta["_bearing_from_company"].notna().sum()),
                    "downwind_station_count_45deg": int(meta["_downwind_45deg"].sum()),
                    "peak_hour_downwind_vs_other_mean": grp.to_dict()
